                for j in range(i-5, i):
                    if j >= 0 and lines[j].strip() and not lines[j].startswith('(') and 'Page' not in lines[j]:
                        project_name = lines[j].strip()
                        if project_name and len(project_name) > 10 and not project_name.startswith('•'):
