    text = doc.get('text', '')

    # Look for spring 2022 references and project names
    # Pattern for "Spring 2022" or "2022-Spring" or "2022-March" etc.
    spring_2022_pattern = r'(spring\s+2022|2022-spring|2022-0[3-5]|2022-march|2022-april|2022-may)'

